// ── Build workbook ─────────────────────────────────────────────
const wb = XLSX.utils.book_new()

const bdWs   = XLSX.utils.json_to_sheet(birthday,     { header: ['verse_reference','verse_text_english','verse_text_tamil_reference','verse_text_tamil','is_active'] })
const annWs  = XLSX.utils.json_to_sheet(anniversary,  { header: ['verse_reference','verse_text_english','verse_text_tamil_reference','verse_text_tamil','is_active'] })

// Column widths
const colWidths = [{ wch: 28 }, { wch: 100 }, { wch: 28 }, { wch: 80 }, { wch: 10 }]
bdWs['!cols']  = colWidths
annWs['!cols'] = colWidths

XLSX.utils.book_append_sheet(wb, bdWs,  'Birthdays')
XLSX.utils.book_append_sheet(wb, annWs, 'Anniversaries')

const outDir  = path.join(process.cwd(), 'public')
if (!fs.existsSync(outDir)) fs.mkdirSync(outDir, { recursive: true })
const outPath = path.join(outDir, 'BibleVerses.xlsx')

XLSX.writeFile(wb, outPath)
console.log(`✅  Created ${outPath}`)
console.log(`    Birthday verses   : ${birthday.length}`)
console.log(`    Anniversary verses: ${anniversary.length}`)
